// Pseudocode for the harness (mirroring existing TryShowPanelByName pattern)

private static IEnumerator ShowWeb3ConfirmationPopup(object dynamicContainer, Report report)
{
    var marker = new PhaseMarker { label = "web3confirm_popup", ok = true };
    report.actions.Add(marker);

    try
    {
        // Option A: Real Donations action
        object donationsService = GetPrivateField(dynamicContainer, "donationsService"); // TODO(LIVE): verify field name
        if (donationsService != null)
        {
            // Trigger donation of 1 MANA to a test address (Evaristo's own address is safe)
            string testRecipient = ViewDependencies.CurrentIdentity?.Address ?? "0x0000000000000000000000000000000000000000";
            object task = donationsService.GetType()
                .GetMethod("SendDonationAsync", BindingFlags.Public | BindingFlags.Instance)
                .Invoke(donationsService, new object[] { testRecipient, 1m, CancellationToken.None });

            // The ethereumApi.SendAsync inside will fire the confirmation popup asynchronously
            // Wait for the user to complete or timeout
            yield return AwaitUniTask(task); // 15s timeout per existing harness pattern

            if (awaitedError != null)
                marker.error = "donation-send failed: " + awaitedError;
            else
                marker.error = "donation-send succeeded (tx hash: " + awaitedResult?.ToString() + ")";
        }
        else
        {
            // Option B: Direct EthApiRequest
            object ethereumApi = GetPrivateField(dynamicContainer, "ethereumApi"); // TODO(LIVE): verify field name
            if (ethereumApi == null) { marker.error = "ethereumApi not found"; yield break; }

            Type ethReqType = FindType("DCL.Web3.EthApiRequest");
            object request = Activator.CreateInstance(ethReqType);
            // Set properties: method="personal_sign", @params=[message, address], id=hashCode
            ethReqType.GetProperty("method").SetValue(request, "personal_sign");
            ethReqType.GetProperty("@params").SetValue(request, new object[] { "Test message", "0x..." });
            ethReqType.GetProperty("id").SetValue(request, Guid.NewGuid().GetHashCode());

            object task = ethereumApi.GetType()
                .GetMethod("SendAsync", BindingFlags.Public | BindingFlags.Instance)
                .Invoke(ethereumApi, new object[] { request, Web3RequestSource.Internal, CancellationToken.None });

            yield return AwaitUniTask(task);
            if (awaitedError != null)
                marker.error = "personal_sign failed: " + awaitedError;
            else
                marker.error = "personal_sign succeeded: " + awaitedResult?.ToString();
        }
    }
    catch (Exception e)
    {
        marker.ok = false;
        marker.error = "web3confirm exception: " + e.Message;
    }

    // Let popup settle after action
    for (int i = 0; i < 30; i++) yield return null;

    // Screenshot the final popup state or world after action
    yield return CaptureShot("web3confirm_final");
}
```

